<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***BagianUrutanFixer*Fixduplicateurutanvaluesinbagiantable*/require_once__DIR__.'/../core/config.php';require_once__DIR__.'/../core/Database.php';require_once__DIR__.'/APIResponse.php';classBagianUrutanFixer{private$pdo;publicfunction__construct(){$db=Database::getInstance();$this->pdo=$db->getConnection();}/***Fixallduplicateurutaninbagiantable*/publicfunctionfixDuplicateUrutan(){$results=[];try{/Getallduplicateurutangroups$duplicates=$this->getDuplicateUrutan();if(empty($duplicates)){return['success'=>true,'message'=>'Noduplicateurutanfound','fixed_count'=>0,'timestamp'=>date('c')];}$fixed_count=0;forforeach($duplicatesas$duplicate){$fix_result=$this->fixDuplicateGroup($duplicate);$results[]=$fix_result;$fixed_count+=$fix_result['fixed_count'];}return['success'=>true,'message'=>"Fixed{$fixed_count}duplicateurutanvalues",'results'=>$results,'fixed_count'=>$fixed_count,'timestamp'=>date('c')];}catch(Exception$e){return['success'=>false,'message'=>'Errorfixingduplicateurutan:'.$e->getMessage(),'timestamp'=>date('c')];}}/***Getallduplicateurutangroups*/privatefunctiongetDuplicateUrutan(){$sql="SELECTid_unsur,urutan,COUNT(*)asduplicate_count,GROUP_CONCAT(idORDERBYid)asbagian_ids,GROUP_CONCAT(nama_bagianORDERBYnama_bagian)asbagian_namesFROMbagianGROUPBYid_unsur,urutanHAVINGCOUNT(*)>1ORDERBYid_unsur,urutan";$stmt=$this->pdo->query($sql);return$stmt->fetchAll(PDO::FETCH_ASSOC);}/***Fixduplicateurutanforaspecificgroup*/privatefunctionfixDuplicateGroup($duplicate){$id_unsur=$duplicate['id_unsur'];$original_urutan=$duplicate['urutan'];$bagian_ids=explode(',',$duplicate['bagian_ids']);$fixed_count=0;$updates=[];/Getmaxurutanforthisunsur$stmt=$this->pdo->prepare("SELECTMAX(urutan)asmax_urutanFROMbagianWHEREid_unsur=?");$stmt->execute([$id_unsur]);$max_urutan=$stmt->fetch()['max_urutan'];/Starttransaction$this->pdo->beginTransaction();try{/Keepfirstrecordwithoriginalurutan$first_id=array_shift($bagian_ids);/Updateremainingrecordswithnewurutanvalues$new_urutan=$max_urutan+1;forforeach($bagian_idsas$bagian_id){$update_sql="UPDATEbagianSETurutan=?,updated_at=NOW()WHEREid=?";$stmt=$this->pdo->prepare($update_sql);$result=$stmt->execute([$new_urutan,$bagian_id]);if($result){$updates[]=['bagian_id'=>$bagian_id,'old_urutan'=>$original_urutan,'new_urutan'=>$new_urutan];$fixed_count++;$new_urutan++;}}$this->pdo->commit();return['id_unsur'=>$id_unsur,'original_urutan'=>$original_urutan,'duplicate_count'=>$duplicate['duplicate_count'],'fixed_count'=>$fixed_count,'updates'=>$updates,'status'=>'success'];}catch(Exception$e){$this->pdo->rollBack();return['id_unsur'=>$id_unsur,'original_urutan'=>$original_urutan,'duplicate_count'=>$duplicate['duplicate_count'],'fixed_count'=>0,'error'=>$e->getMessage(),'status'=>'error'];}}/***Verifyurutanuniquenessafterfix*/publicfunctionverifyUrutanUniqueness(){$sql="SELECTid_unsur,urutan,COUNT(*)ascountFROMbagianGROUPBYid_unsur,urutanHAVINGCOUNT(*)>1";$stmt=$this->pdo->query($sql);$remaining_duplicates=$stmt->fetchAll(PDO::FETCH_ASSOC);return['success'=>empty($remaining_duplicates),'remaining_duplicates'=>$remaining_duplicates,'is_unique'=>empty($remaining_duplicates),'timestamp'=>date('c')];}}/Executeifaccesseddirectlyif(basename($_SERVER['PHP_SELF'])===basename(__FILE__)){header('Content-Type:application/json');try{$fixer=newBagianUrutanFixer();/Fixduplicates$fix_result=$fixer->fixDuplicateUrutan();/Verifyafterfix$verify_result=$fixer->verifyUrutanUniqueness();echojson_encode(APIResponse::success(['fix_result'=>$fix_result,'verification'=>$verify_result],'Bagianurutanfixcompleted'));}catch(Exception$e){echojson_encode(APIResponse::error($e->getMessage(),500));}}?>
